import Swiper, { Pagination, Autoplay, Navigation } from "swiper";
Swiper.use([Pagination, Autoplay, Navigation]);

class Gallery {
  constructor(config) {
    this.section = config.section;

    this.initSwiper();
  }

  initSwiper = () => {
    let swiper = this.section;
    new Swiper(swiper, {
      speed: 400,
      spaceBetween: 0,
      loop: true,
      slidesPerView: 1,
      autoplay: {
        delay: 5000,
      },
      navigation: {
        nextEl: this.section.querySelector(".gallery__controls--next"),
        prevEl: this.section.querySelector(".gallery__controls--prev"),
      },
      pagination: {
        el: this.section.querySelector(".swiper-pagination"),
        type: "bullets",
        clickable: true,
        bulletClass: "bullet backgroundcolor--primary",
        bulletActiveClass: "bullet--active backgroundcolor--secondary",
      },
    });
  };
}

export default Gallery;
