import axios from "axios";

class TeamTable {
  constructor(config) {
    this.section = config.section;

    this.gameTableYearSelect = this.section.querySelector(
      ".teamtable__yearselect"
    );

    this.headerEL = this.section.querySelector(".teamtable__header");
    this.filtersEL = this.section.querySelector(".teamtable__filters");
    this.tableEL = this.section.querySelector(".teamtable__table");
    this.headEL = this.section.querySelector(".teamtable__head");
    this.rowsWrapperEL = this.section.querySelector(".teamtable__rowsWrapper");
    this.rowsEL = this.section.querySelector(".teamtable__rows");

    this.teamId = this.section.dataset.team;
    this.year = this.section.dataset.year;
    this.gamesPerPage = 100;

    this.addEventListeners();

    this.onChangeYearSelect();
  }

  addEventListeners = () => {
    this.gameTableYearSelect.addEventListener(
      "change",
      this.onChangeYearSelect
    );
  };

  onChangeYearSelect = (e) => {
    this.year = this.gameTableYearSelect.value;
    this.fireRequest();
  };

  fireRequest = () => {
    const ajaxUrl = `${window.apiBaseUrl}/rankings?season=${this.year}&team_id=${this.teamId}`;

    const data = {};

    axios
      .get(ajaxUrl, data, {
        headers: this.headers,
      })
      .then((response) => {
        this.renderTable(response.data.data);
      })
      .catch((error) => {
        console.log(error);
        this.headerEL.innerHTML = "";
        this.rowsEL.innerHTML = "";
        this.headEL.innerHTML = "";
        const titleEl = document.createElement("h5");
        titleEl.classList.add("teamtable__title");
        titleEl.innerText = `Für dieses Team steht (noch) keine Tabelle der Saison ${this.year} zur Verfügung.`;
        this.rowsEL.appendChild(titleEl);
      });
  };

  renderTable = (data) => {
    const headers = data.headers.map((v) => {
      return v.text;
    });

    this.headerEL.innerHTML = "";
    this.rowsEL.innerHTML = "";
    this.headEL.innerHTML = "";

    // Title
    const titleEl = document.createElement("h4");
    titleEl.classList.add("teamtable__title");
    titleEl.innerText = data.title;
    this.headerEL.appendChild(titleEl);

    // Table/Teams
    if (data.regions.length) {
      // Table Head
      headers.forEach((header) => {
        const el = document.createElement("h6");
        el.classList.add("teamtable__headCell");
        el.innerText = header;
        this.headEL.appendChild(el);
      });

      const teams = data.regions[0]["rows"];
      teams.forEach((team) => {
        const teamEl = document.createElement("div");
        if (team.data.team.id == this.teamId) {
          teamEl.classList.add("color--primary", "current");
        }
        teamEl.classList.add("teamtable__row");
        teamEl.dataset.id = team.data.team.id;
        team.cells.forEach((value) => {
          const cellEl = document.createElement("div");
          cellEl.classList.add("teamtable__rowCell");
          if ("text" in value) {
            cellEl.innerText = value.text[0];
          } else {
            const img = document.createElement("img");
            img.src = value.image.url;
            cellEl.appendChild(img);
          }
          teamEl.appendChild(cellEl);
        });
        this.rowsEL.appendChild(teamEl);
      });
    } else {
      const titleEl = document.createElement("h5");
      titleEl.classList.add("teamtable__title");
      titleEl.innerText = `Für dieses Team steht (noch) keine Tabelle der Saison ${this.year} zur Verfügung.`;
      this.rowsEL.appendChild(titleEl);
    }
  };
}

export default TeamTable;
