import axios from "axios";

class AdabsContent {
  constructor() {
    this.sendRequest();
    this.imprintContent;
    this.footerContent;
    this.sidebarContent;
  }

  sendRequest = () => {
    const ajaxUrl = `https://swissunihockey.adabs.ch/wp-json/api/getinfo/`;

    const data = {};

    axios
      .get(ajaxUrl, data, {
        headers: this.headers,
      })
      .then((response) => {
        this.setImprint(response);
        this.setFooter(response);
        this.setSidebar(response);
      })
      .catch((error) => {
        console.log(error);
      });
  };

  setImprint = (response) => {
    this.imprintContent = response.data.data.imprint;
    if (
      this.imprintContent.length &&
      document.querySelector("body").classList.contains("page-id-195")
    ) {
      const main = document.querySelector("main");
      const textEl = document.createElement("section");
      textEl.classList.add("text");
      const textWrapperEl = document.createElement("div");
      textWrapperEl.classList.add("text__wrapper");
      textWrapperEl.innerHTML = this.imprintContent;
      textEl.appendChild(textWrapperEl);
      main.appendChild(textEl);
    }
  };

  setFooter = (response) => {
    this.footerContent = response.data.data.footer;
    if (this.footerContent.length) {
      const footerLower = document.querySelector(".footer__lower");
      const wrapper = document.createElement("div");
      wrapper.classList.add(
        "footer__wrapper",
        "footer__wrapper--api",
        "contentwidth"
      );
      wrapper.innerHTML = this.footerContent;
      footerLower.appendChild(wrapper);
    }
  };

  setSidebar = (response) => {
    this.sidebarContent = response.data.data.sidebar;
    const aside = document.querySelector("aside");
    if (aside && this.sidebarContent.length) {
      // Disclaimer
      const section = document.createElement("section");
      section.classList.add("text");
      const wrapper = document.createElement("div");
      wrapper.classList.add("text__wrapper");
      wrapper.innerHTML =
        "Inhalte von <a href='https://swissunihockey.ch'>swissunihockey.ch</a>";
      wrapper.innerHTML = "Werbung";
      section.appendChild(wrapper);
      aside.appendChild(section);

      this.sidebarContent.forEach((el) => {
        if (el.acf_fc_layout == "text") {
          const section = document.createElement("section");
          section.classList.add(
            "text",
            `backgroundcolor--${el.bgcolor}`,
            `contrastcolor--${el.bgcolor}`
          );
          const wrapper = document.createElement("div");
          wrapper.classList.add("text__wrapper");
          wrapper.innerHTML = el["text"];
          section.appendChild(wrapper);
          aside.appendChild(section);
        } else if (el.acf_fc_layout == "image") {
          const section = document.createElement("section");
          section.classList.add("image");
          const wrapper = document.createElement("div");
          wrapper.classList.add("image__wrapper");
          const img = document.createElement("img");
          img.classList.add("image__image");
          img.src = el.image.url;

          if (el.url.length) {
            const ahref = document.createElement("a");
            ahref.href = el.url;
            ahref.target = "_blank";
            ahref.rel = "noopener";
            ahref.appendChild(img);
            wrapper.appendChild(ahref);
          } else {
            wrapper.appendChild(img);
          }

          section.appendChild(wrapper);
          aside.appendChild(section);
        }
      });
    }
  };
}

export default AdabsContent;
