class Overlay {
  constructor() {
    this.section = document.querySelector(".overlay");
    this.closeButton = this.section.querySelector("#overlayclosebutton");
    this.contentWrapper = this.section.querySelector(".overlay__content");

    this.addEventListeners();
  }

  addEventListeners = () => {
    this.closeButton.addEventListener("click", this.hideOverlay);
  };

  hideOverlay = () => {
    this.section.classList.remove("active");
    this.contentWrapper.innerHTML = "";
  };

  showOverlay = (html) => {
    this.contentWrapper.innerHTML = html;
    this.section.classList.add("active");
  };
}

export default Overlay;
