"use strict";

import "babel-polyfill";
import AdabsContent from "./components/AdabsContent";
import Gallery from "./components/Gallery";
import GameTable from "./components/GameTable";
// import Swiper from "swiper";
import GACE from "./components/googleAnalyticsCustomEvents";
import Overlay from "./components/Overlay";
import TeamTable from "./components/TeamTable";

Array.prototype.shuffle = function () {
  return this.sort(function () {
    return Math.random() - 0.5;
  });
};

Array.prototype.getRandomValue = function () {
  return this.shuffle()[0];
};

Array.prototype.uniqueValues = function () {
  return [...new Set(this)];
};

document.addEventListener("DOMContentLoaded", function () {
  // set GA-ID
  // const gace = new GACE({
  //   id: "UA-164327129-1",
  // });
  // var mySwiper = new Swiper(".gallery", {
  //   speed: 400,
  //   spaceBetween: 0,
  // });

  const overlay = new Overlay();

  window.apiBaseUrl = "https://wc.swissunihockey.ch/";

  const gametables = [...document.querySelectorAll(".gametable")];
  gametables.forEach((section) => {
    new GameTable({
      section: section,
      overlay: overlay,
    });
  });

  const teamtables = [...document.querySelectorAll(".teamtable")];
  teamtables.forEach((section) => {
    new TeamTable({ section: section });
  });

  const galleries = [...document.querySelectorAll(".gallery")];
  galleries.forEach((gallery) => {
    new Gallery({ section: gallery });
  });

  new AdabsContent();
});
