import axios from "axios";

class GameTable {
  constructor(config) {
    this.section = config.section;
    this.overlay = config.overlay;

    this.gameTableYearSelect = this.section.querySelector(
      ".gametable__yearselect"
    );
    this.gameTableTeamSelect = this.section.querySelector(
      ".gametable__teamselect"
    );

    this.headerEL = this.section.querySelector(".gametable__header");
    this.filtersEL = this.section.querySelector(".gametable__filters");
    this.tableEL = this.section.querySelector(".gametable__table");
    this.headEL = this.section.querySelector(".gametable__head");
    this.rowsWrapperEL = this.section.querySelector(".gametable__rowsWrapper");
    this.rowsEL = this.section.querySelector(".gametable__rows");

    this.teamId = this.section.dataset.team;
    if (!this.teamId) {
      this.teamId = this.gameTableTeamSelect.value;
    }
    this.year = this.section.dataset.year;
    this.gamesPerPage = 100;

    this.addEventListeners();

    this.onChangeYearSelect();
  }

  addEventListeners = () => {
    this.gameTableYearSelect.addEventListener(
      "change",
      this.onChangeYearSelect
    );

    if (this.gameTableTeamSelect) {
      this.gameTableTeamSelect.addEventListener(
        "change",
        this.onChangeTeamSelect
      );
    }
  };

  onChangeYearSelect = (e) => {
    this.year = this.gameTableYearSelect.value;
    this.fireRequest();
  };

  onChangeTeamSelect = (e) => {
    this.teamId = this.gameTableTeamSelect.value;
    this.fireRequest();
  };

  fireRequest = () => {
    const ajaxUrl = `${window.apiBaseUrl}/games?mode=team&season=${this.year}&team_id=${this.teamId}&page=1&games_per_page=${this.gamesPerPage}`;
    // console.log(ajaxUrl);

    const data = {};

    axios
      .get(ajaxUrl, data, {
        headers: this.headers,
      })
      .then((response) => {
        this.renderTable(response.data.data);
      })
      .catch((error) => {
        console.log(error);
        if (error.response.data.message.includes("Invalid page value")) {
          this.headerEL.innerHTML = "";
          this.rowsEL.innerHTML = "";
          const titleEl = document.createElement("h5");
          titleEl.classList.add("gametable__title");
          titleEl.innerText = `Für dieses Team wurden (noch) keine Spiele Spiele der Saison ${this.year} gefunden.`;
          this.headerEL.appendChild(titleEl);
        }
      });
  };

  renderTable = (data) => {
    // console.log(data);
    const headers = data.headers.map((v) => {
      return v.text;
    });

    // Title
    this.headerEL.innerHTML = "";
    const titleEl = document.createElement("h4");
    titleEl.classList.add("gametable__title");
    titleEl.innerText = data.title;
    this.headerEL.appendChild(titleEl);

    // Table Head
    this.headEL.innerHTML = "";
    headers.forEach((header) => {
      const el = document.createElement("h6");
      el.classList.add("gametable__headCell");
      el.innerText = header;
      this.headEL.appendChild(el);
    });
    const el = document.createElement("h6");
    el.classList.add("gametable__headCell", "gametable__headCell--info");
    el.innerText = "Bericht";
    this.headEL.appendChild(el);

    // Table/Games
    this.rowsEL.innerHTML = "";
    const games = data.regions[0]["rows"];
    games.forEach((game) => {
      const gameEl = document.createElement("div");
      gameEl.classList.add("gametable__row");
      gameEl.dataset.id = game.link.ids[0];
      let text = "";
      game.cells.forEach((value) => {
        const cellEl = document.createElement("div");
        cellEl.classList.add("gametable__rowCell");
        text = value.text.join(", ");
        cellEl.innerText = text;
        if (value.highlight) {
          cellEl.classList.add("current", "color--primary");
        }
        gameEl.appendChild(cellEl);
      });

      if (text.length && text != "-:-") {
        const cellEl = document.createElement("div");
        cellEl.classList.add("gametable__rowCell", "gametable__rowCell--info");
        const wrapper = document.createElement("div");
        wrapper.classList.add("gametable__infoWrapper");
        wrapper.innerHTML = `
        <canvas width="24" height="24"></canvas>
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M12 0C5.373 0 0 5.373 0 12C0 18.627 5.373 24 12 24C18.627 24 24 18.627 24 12C24 5.373 18.627 0 12 0ZM13 18H11V11H13V18ZM12 8.5C11.172 8.5 10.5 7.828 10.5 7C10.5 6.172 11.172 5.5 12 5.5C12.828 5.5 13.5 6.172 13.5 7C13.5 7.828 12.828 8.5 12 8.5Z" fill="black"/>
        </svg>
      `;
        cellEl.appendChild(wrapper);
        gameEl.appendChild(cellEl);
        cellEl.addEventListener("click", (e) => {
          this.onClickGame(gameEl);
        });
      }
      this.rowsEL.appendChild(gameEl);
    });
  };

  onClickGame = (gameEl) => {
    const gameId = gameEl.dataset.id;
    const ajaxUrl = `${window.apiBaseUrl}/games/${gameId}/summary`;
    // console.log(ajaxUrl);

    const data = {};

    axios
      .get(ajaxUrl, data, {
        headers: this.headers,
      })
      .then((response) => {
        console.log(response);
        const data = response.data.data;
        const title = data.title;
        const subtitle = data.subtitle;
        const info = data.regions[0].rows[0].cells[1].text[0];
        const goals = data.regions[0].rows[0].cells[2].text[0];
        const penalties = data.regions[0].rows[0].cells[2].text[1];
        const html = `
          <h1>${title}</h1>
          <h3>${subtitle}</h3>
          <p>${goals}</p>
          <p>${penalties}</p>
        `;
        this.overlay.showOverlay(html);
      })
      .catch((error) => {
        console.log(error);
      });
  };
}

export default GameTable;
